/// <summary>
/// this class is extends of srs report for the new customization fields.
/// </summary>
class ETGSalestaxinvoicecontroller extends SrsReportRunController
{
}

Method.Source:
Protected void preRunModifyContract()
{
    CustInvoiceJour            custInvoiceJour;
    ETGSalesTaxinvoiceContract contract;
    contract = this.parmReportContract().parmRdpContract() as ETGSalesTaxinvoiceContract;
    if(this.parmArgs().dataset() == tableNum(custInvoiceJour))
    {
        custInvoiceJour = this.parmArgs().record();
    }
        contract.parmSalesId(custInvoiceJour.SalesId);
        contract.parmInvoiceId(custInvoiceJour.InvoiceId);
}

public static void main(args _args)
{

    ETGSalestaxinvoicecontroller controller = new ETGSalestaxinvoicecontroller();
    controller.parmReportName(ssrsReportStr(SalesinvoiceReport,ETGReport));
    controller.parmArgs(_args);
    controller.parmShowDialog(false);
    controller.startOperation();
}
